#include <bits/stdc++.h>
using namespace std;

const int N=1e6+6;

struct Node{
	int id,val;
}t[N];

int n,l,r,a[N],pre[N],nxt[N],last[N],mx[N],cnt;

bool cmp(Node x,Node y){
	return x.val>y.val;
}

int main(){
	scanf("%d%d%d",&n,&l,&r);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for(int i=1;i<=n;i++){
		pre[i]=last[a[i]];
		last[a[i]]=i;
	}
	for(int i=1;i<=1e6;i++)
		last[i]=n+1;
	for(int i=n;i;i--){
		nxt[i]=last[a[i]];
		last[a[i]]=i;
	}
	for(int i=1;i<l;i++)
		if(pre[i]==0)
			t[++cnt]={i,nxt[i]};
	sort(t+1,t+cnt+1,cmp);
	int ans=1e8;
	for(int i=n,j=1,mx=0;i>r;i--){
		if(nxt[i]==n+1){
			while(t[j].val>i && j<=cnt)
				mx=max(mx,t[j].id),j++;
			if(mx>pre[i])
				ans=min(ans,i-mx+1);
		}
	}
	if(ans==1e8)
		printf("-1");
	else
		printf("%d",ans);
	return 0;
}
